"use client";

import { useState, useRef } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  getRandomComplete,
  getRandomEncourage,
  triggerShake,
} from "@/lib/learningMessages";
import { playClick, playFlip, playCelebrate } from "@/lib/sounds";

// 星期表头：周日 ~ 周六
const WEEK_HEADERS = ["日", "一", "二", "三", "四", "五", "六"];

interface SpecialDate {
  emoji: string;
  label: string;
}

interface MonthData {
  name: string;
  days: number;
  /** 1 号是星期几（0=周日） */
  firstDayWeek: number;
  specials: Record<number, SpecialDate>;
}

// 固定数据：2026 年 6/7/8 月
// 6月1日=周一(1)，7月1日=周三(3)，8月1日=周六(6)
const MONTHS: MonthData[] = [
  {
    name: "六月",
    days: 30,
    firstDayWeek: 1,
    specials: { 1: { emoji: "🎈", label: "儿童节" } },
  },
  {
    name: "七月",
    days: 31,
    firstDayWeek: 3,
    specials: {
      1: { emoji: "🎉", label: "建党节" },
      15: { emoji: "🎂", label: "我的生日" },
    },
  },
  {
    name: "八月",
    days: 31,
    firstDayWeek: 6,
    specials: { 1: { emoji: "🎖", label: "建军节" } },
  },
];

// “今天” = 2026 年 7 月 14 日（仅作视觉标记）
const TODAY_MONTH = 1;
const TODAY_DAY = 14;

// 把所有特殊日期摊平成清单，用于进度展示
const SPECIAL_LIST = MONTHS.flatMap((m, mi) =>
  Object.entries(m.specials).map(([d, s]) => ({
    key: `${mi}-${d}`,
    emoji: s.emoji,
    label: s.label,
    hint: `${m.name}${d}日`,
  }))
);
const TOTAL_SPECIAL = SPECIAL_LIST.length;

interface Toast {
  text: string;
  shake: boolean;
}

export default function TouchPage() {
  const topicId = "calendar";
  const [monthIdx, setMonthIdx] = useState(1); // 默认展示七月
  const [found, setFound] = useState<Set<string>>(new Set());
  const [completeMsg, setCompleteMsg] = useState("");
  const [toast, setToast] = useState<Toast | null>(null);
  const calRef = useRef<HTMLDivElement>(null);

  const month = MONTHS[monthIdx];
  const isDone = found.size >= TOTAL_SPECIAL;
  const nextStep = getNextStep(topicId, "touch");

  const handleCellClick = (day: number) => {
    if (isDone) return;
    const key = `${monthIdx}-${day}`;
    const special = month.specials[day];
    const isToday = monthIdx === TODAY_MONTH && day === TODAY_DAY;

    if (special) {
      if (found.has(key)) return;
      const next = new Set(found);
      next.add(key);
      setFound(next);
      setToast(null);
      playFlip();
      if (next.size >= TOTAL_SPECIAL) {
        setCompleteMsg(getRandomComplete());
        setTimeout(() => playCelebrate(), 300);
      }
    } else if (isToday) {
      setToast({ text: "📍 这就是今天：7 月 14 日", shake: false });
    } else {
      setToast({ text: getRandomEncourage(), shake: true });
      triggerShake(calRef.current);
    }
  };

  // 构造当月格子：前置空格 + 日期 + 后置补齐到 42（6 行，保持高度一致）
  const cells: (number | null)[] = [];
  for (let i = 0; i < month.firstDayWeek; i++) cells.push(null);
  for (let d = 1; d <= month.days; d++) cells.push(d);
  while (cells.length < 42) cells.push(null);

  return (
    <StepShell topicId={topicId} stepId="touch">
      <div className="space-y-6">
        {/* 说明 + 进度 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <h2 className="text-lg font-bold text-[var(--text)]">翻翻日历，找一找</h2>
          <p className="mt-1 text-sm text-[var(--text-secondary)]">
            点击日历上高亮的特殊日期，把它们都找出来吧！
          </p>

          <div className="mt-3 flex flex-wrap items-center gap-2">
            <span className="rounded-full bg-[var(--bg-soft)] px-3 py-1 text-sm font-medium text-[var(--text-secondary)]">
              已找到{" "}
              <span className="font-bold text-[var(--primary)]">{found.size}</span>{" "}
              / {TOTAL_SPECIAL}
            </span>
            {toast && (
              <span
                className={`animate-float-in rounded-full px-3 py-1 text-sm font-medium ${
                  toast.shake
                    ? "bg-[var(--signal-shake)]/15 text-[var(--signal-shake)]"
                    : "bg-[var(--primary)]/15 text-[var(--primary-dark)]"
                }`}
              >
                {toast.text}
              </span>
            )}
          </div>

          {/* 找一找清单 */}
          <div className="mt-3 flex flex-wrap gap-2">
            {SPECIAL_LIST.map((s) => {
              const ok = found.has(s.key);
              return (
                <span
                  key={s.key}
                  className={`rounded-full px-3 py-1 text-xs font-medium transition-all ${
                    ok
                      ? "bg-[var(--signal-success)]/20 text-[var(--signal-success)]"
                      : "bg-[var(--bg-soft)] text-[var(--text-muted)]"
                  }`}
                >
                  {ok ? "✓ " : ""}
                  {s.emoji} {s.label}
                  <span className="ml-1 opacity-70">（{s.hint}）</span>
                </span>
              );
            })}
          </div>
        </div>

        {/* 日历主体 */}
        <div
          ref={calRef}
          className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]"
        >
          {/* 月份切换 */}
          <div className="mb-4 flex items-center justify-between">
            <button
              onClick={() => { setMonthIdx((i) => Math.max(0, i - 1)); playClick(); }}
              disabled={monthIdx === 0}
              className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)] disabled:opacity-30"
            >
              ← 上个月
            </button>
            <div className="text-center">
              <div className="text-2xl font-extrabold text-[var(--text)]">
                2026 年 {month.name}
              </div>
              <div className="text-xs text-[var(--text-muted)]">
                共 {month.days} 天
              </div>
            </div>
            <button
              onClick={() => {
                setMonthIdx((i) => Math.min(MONTHS.length - 1, i + 1));
                playClick();
              }}
              disabled={monthIdx === MONTHS.length - 1}
              className="rounded-full border border-[var(--border)] px-4 py-2 text-sm font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)] disabled:opacity-30"
            >
              下个月 →
            </button>
          </div>

          {/* 星期表头 */}
          <div className="grid grid-cols-7 gap-1.5">
            {WEEK_HEADERS.map((w) => (
              <div
                key={w}
                className="py-1 text-center text-xs font-bold text-[var(--text-muted)]"
              >
                {w}
              </div>
            ))}
          </div>

          {/* 日期格子 */}
          <div key={monthIdx} className="mt-1 grid grid-cols-7 gap-1.5">
            {cells.map((day, i) => {
              if (day === null) {
                return <div key={i} className="aspect-square" />;
              }
              const key = `${monthIdx}-${day}`;
              const special = month.specials[day];
              const isFound = found.has(key);
              const isToday = monthIdx === TODAY_MONTH && day === TODAY_DAY;

              let bg = "transparent";
              let border = "2px solid transparent";
              let textColor = "var(--text)";

              if (special && isFound) {
                bg = "var(--signal-success)";
                border = "2px solid var(--signal-success)";
                textColor = "#ffffff";
              } else if (special) {
                bg = "var(--accent3-light)";
                border = "2px solid var(--accent3)";
                textColor = "var(--text)";
              } else if (isToday) {
                border = "2px solid var(--primary)";
                textColor = "var(--primary-dark)";
              }

              return (
                <button
                  key={i}
                  onClick={() => handleCellClick(day)}
                  className="relative flex aspect-square cursor-pointer flex-col items-center justify-center rounded-[var(--radius-xs)] transition-all hover:scale-[1.04] active:scale-95"
                  style={{ backgroundColor: bg, border }}
                >
                  {special ? (
                    <>
                      <span
                        className="absolute left-1 top-0.5 text-[10px] font-bold"
                        style={{ color: textColor }}
                      >
                        {day}
                      </span>
                      <span className="text-lg leading-none">
                        {special.emoji}
                      </span>
                      <span
                        className="mt-0.5 px-0.5 text-center text-[9px] leading-tight"
                        style={{
                          color: isFound ? "#ffffff" : "var(--text-secondary)",
                        }}
                      >
                        {isFound ? "✓ 已找到" : special.label}
                      </span>
                    </>
                  ) : (
                    <span
                      className="text-base font-bold"
                      style={{ color: textColor }}
                    >
                      {day}
                    </span>
                  )}
                  {isToday && !special && (
                    <span className="absolute right-1 top-0.5 text-[9px] font-bold text-[var(--primary)]">
                      今
                    </span>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* 完成卡片 */}
        {isDone && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">📅</div>
            <h3 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h3>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你找到了全部 {TOTAL_SPECIAL} 个特殊日期！日历里藏着好多有意思的日子呢。
            </p>
            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              <button
                onClick={() => {
                  setFound(new Set());
                  setCompleteMsg("");
                  setToast(null);
                  setMonthIdx(1);
                }}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
              >
                再玩一次
              </button>
              {nextStep && (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一步：{nextStep.label} →
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
